patch:
diff --git a/llvm/lib/Transforms/Scalar/LoopUnrollAndJamPass.cpp b/llvm/lib/Transforms/Scalar/LoopUnrollAndJamPass.cpp
index f1d1f3bc1e30..ba16ec05367a 100644
--- a/llvm/lib/Transforms/Scalar/LoopUnrollAndJamPass.cpp
+++ b/llvm/lib/Transforms/Scalar/LoopUnrollAndJamPass.cpp
@@ -432,10 +432,20 @@ static bool tryToUnrollAndJamLoop(LoopNest &LN, DominatorTree &DT, LoopInfo &LI,

   // Add the loop nests in the reverse order of LN. See method
   // declaration.
+  // Filter out any invalid loops that may have been deleted by previous passes.
+  SmallVector<Loop*, 4> ValidLoops;
+  for (Loop *L : Loops) {
+    if (!L->isInvalid())
+      ValidLoops.push_back(L);
+  }
   SmallPriorityWorklist<Loop *, 4> Worklist;
-  appendLoopsToWorklist(Loops, Worklist);
+  if (!ValidLoops.empty())
+    appendLoopsToWorklist(ValidLoops, Worklist);
   while (!Worklist.empty()) {
     Loop *L = Worklist.pop_back_val();
+    // Skip invalid loops that may have been deleted by previous transformations.
+    if (L->isInvalid())
+      continue;
     std::string LoopName = std::string(L->getName());
     LoopUnrollResult Result =
         tryToUnrollAndJamLoop(L, DT, &LI, SE, TTI, AC, DI, ORE, OptLevel);
diff --git a/llvm/lib/Transforms/Utils/LoopUtils.cpp b/llvm/lib/Transforms/Utils/LoopUtils.cpp
index f57d95e7722d..fe8c15430aff 100644
--- a/llvm/lib/Transforms/Utils/LoopUtils.cpp
+++ b/llvm/lib/Transforms/Utils/LoopUtils.cpp
@@ -1826,6 +1826,10 @@ template void
 llvm::appendLoopsToWorklist<Loop &>(Loop &L,
                                     SmallPriorityWorklist<Loop *, 4> &Worklist);

+template void
+llvm::appendLoopsToWorklist<llvm::SmallVector<llvm::Loop*, 4> &>(
+    llvm::SmallVector<llvm::Loop*, 4> &Loops, SmallPriorityWorklist<llvm::Loop*, 4> &Worklist);
+
 void llvm::appendLoopsToWorklist(LoopInfo &LI,
                                  SmallPriorityWorklist<Loop *, 4> &Worklist) {
   appendReversedLoopsToWorklist(LI, Worklist);

